FORMULA_COUNTER = 0


def set_font(run, name: str = "Times New Roman", size: int | float = 14, bold: bool | None = None, italic: bool | None = None) -> None:
    run.font.name = name
    run._element.rPr.rFonts.set(qn("w:ascii"), name)
    run._element.rPr.rFonts.set(qn("w:hAnsi"), name)
    run._element.rPr.rFonts.set(qn("w:eastAsia"), name)
    run._element.rPr.rFonts.set(qn("w:cs"), name)
    run.font.size = Pt(size)
    if bold is not None:
        run.bold = bold
    if italic is not None:
        run.italic = italic


def set_paragraph_format(paragraph, *, first_line: bool = True, align=WD_ALIGN_PARAGRAPH.JUSTIFY, before=0, after=0, line=1.5) -> None:
    pf = paragraph.paragraph_format
    pf.first_line_indent = Cm(1.25) if first_line else None
    pf.alignment = align
    pf.space_before = Pt(before)
    pf.space_after = Pt(after)
    pf.line_spacing = line


def add_page_number(paragraph) -> None:
    paragraph.alignment = WD_ALIGN_PARAGRAPH.CENTER
    run = paragraph.add_run()
    fld_begin = OxmlElement("w:fldChar")
    fld_begin.set(qn("w:fldCharType"), "begin")
    instr = OxmlElement("w:instrText")
    instr.set(qn("xml:space"), "preserve")
    instr.text = "PAGE"
    fld_sep = OxmlElement("w:fldChar")
    fld_sep.set(qn("w:fldCharType"), "separate")
    text = OxmlElement("w:t")
    text.text = "1"
    fld_end = OxmlElement("w:fldChar")
    fld_end.set(qn("w:fldCharType"), "end")
    run._r.append(fld_begin)
    run._r.append(instr)
    run._r.append(fld_sep)
    run._r.append(text)
    run._r.append(fld_end)
    set_font(run, size=12)


def shade_cell(cell, fill: str) -> None:
    tc_pr = cell._tc.get_or_add_tcPr()
    shd = tc_pr.find(qn("w:shd"))
    if shd is None:
        shd = OxmlElement("w:shd")
        tc_pr.append(shd)
    shd.set(qn("w:fill"), fill)


def set_cell_text(cell, text: str, *, bold: bool = False, size: int = 12, align=WD_ALIGN_PARAGRAPH.LEFT) -> None:
    cell.vertical_alignment = WD_CELL_VERTICAL_ALIGNMENT.CENTER
    paragraph = cell.paragraphs[0]
    paragraph.alignment = align
    paragraph.paragraph_format.space_after = Pt(0)
    paragraph.paragraph_format.line_spacing = 1.1
    run = paragraph.add_run(str(text))
    set_font(run, size=size, bold=bold)


def add_table(doc: Document, headers: list[str], rows: list[list[object]], widths: list[float] | None = None, font_size: int = 11) -> None:
    table = doc.add_table(rows=1, cols=len(headers))
    table.alignment = WD_TABLE_ALIGNMENT.CENTER
    table.style = "Table Grid"
    hdr = table.rows[0].cells
    for i, header in enumerate(headers):
        shade_cell(hdr[i], "D9EAF7")
        set_cell_text(hdr[i], header, bold=True, size=font_size, align=WD_ALIGN_PARAGRAPH.CENTER)
    for row in rows:
        cells = table.add_row().cells
        for i, value in enumerate(row):
            set_cell_text(cells[i], "" if value is None else value, size=font_size)
    if widths:
        for row in table.rows:
            for idx, width in enumerate(widths):
                row.cells[idx].width = Cm(width)
    doc.add_paragraph()


def add_formula(doc: Document, formula: str, explanation: str | None = None) -> None:
    global FORMULA_COUNTER
    FORMULA_COUNTER += 1
    p = doc.add_paragraph()
    p.alignment = WD_ALIGN_PARAGRAPH.CENTER
    p.paragraph_format.first_line_indent = None
    p.paragraph_format.space_before = Pt(6)
    p.paragraph_format.space_after = Pt(3)
    p.paragraph_format.line_spacing = 1.2
    run = p.add_run(formula)
    set_font(run, size=14, italic=True)
    num = p.add_run(f" ({FORMULA_COUNTER})")
    set_font(num, size=14, italic=False)
    if explanation:
        add_para(doc, explanation, first_line=True)


def add_para(doc: Document, text: str, *, first_line: bool = True, align=WD_ALIGN_PARAGRAPH.JUSTIFY, bold_prefix: str | None = None) -> None:
    p = doc.add_paragraph()
    set_paragraph_format(p, first_line=first_line, align=align)
    if bold_prefix and text.startswith(bold_prefix):
        r1 = p.add_run(bold_prefix)
        set_font(r1, bold=True)
        r2 = p.add_run(text[len(bold_prefix):])
        set_font(r2)
    else:
        run = p.add_run(text)
        set_font(run)


def add_bullet(doc: Document, text: str) -> None:
    p = doc.add_paragraph(style="List Bullet")
    set_paragraph_format(p, first_line=False)
    p.paragraph_format.left_indent = Cm(1.25)
    p.paragraph_format.first_line_indent = Cm(-0.5)
    run = p.add_run(text)
    set_font(run)


def add_number(doc: Document, text: str) -> None:
    p = doc.add_paragraph(style="List Number")
    set_paragraph_format(p, first_line=False)
    p.paragraph_format.left_indent = Cm(1.25)
    p.paragraph_format.first_line_indent = Cm(-0.5)
    run = p.add_run(text)
    set_font(run)


def add_heading(doc: Document, text: str, level: int = 1, *, page_break: bool = False) -> None:
    if page_break:
        doc.add_page_break()
    style = f"Heading {min(level, 3)}"
    p = doc.add_paragraph(style=style)
    p.alignment = WD_ALIGN_PARAGRAPH.CENTER if level == 1 else WD_ALIGN_PARAGRAPH.LEFT
    p.paragraph_format.first_line_indent = None
    p.paragraph_format.space_before = Pt(12 if level == 1 else 8)
    p.paragraph_format.space_after = Pt(8 if level == 1 else 6)
    p.paragraph_format.line_spacing = 1.2
    run = p.add_run(text.upper() if level == 1 else text)
    set_font(run, size=14, bold=True)


def configure_styles(doc: Document) -> None:
    section = doc.sections[0]
    section.page_width = Mm(210)
    section.page_height = Mm(297)
    section.top_margin = Mm(20)
    section.bottom_margin = Mm(20)
    section.left_margin = Mm(30)
    section.right_margin = Mm(10)
    section.header_distance = Mm(12)
    section.footer_distance = Mm(12)
    section.different_first_page_header_footer = True
    add_page_number(section.footer.paragraphs[0])

    normal = doc.styles["Normal"]
    normal.font.name = "Times New Roman"
    normal._element.rPr.rFonts.set(qn("w:ascii"), "Times New Roman")
    normal._element.rPr.rFonts.set(qn("w:hAnsi"), "Times New Roman")
    normal._element.rPr.rFonts.set(qn("w:eastAsia"), "Times New Roman")
    normal._element.rPr.rFonts.set(qn("w:cs"), "Times New Roman")
    normal.font.size = Pt(14)
    normal.paragraph_format.first_line_indent = Cm(1.25)
    normal.paragraph_format.line_spacing = 1.5
    normal.paragraph_format.space_after = Pt(0)

    for name in ["Heading 1", "Heading 2", "Heading 3"]:
        style = doc.styles[name]
        style.font.name = "Times New Roman"
        style._element.rPr.rFonts.set(qn("w:ascii"), "Times New Roman")
        style._element.rPr.rFonts.set(qn("w:hAnsi"), "Times New Roman")
        style._element.rPr.rFonts.set(qn("w:eastAsia"), "Times New Roman")
        style._element.rPr.rFonts.set(qn("w:cs"), "Times New Roman")
        style.font.size = Pt(14)
        style.font.bold = True
        style.font.color.rgb = RGBColor(0, 0, 0)


def load_metrics(result_dir: Path) -> dict:
    path = result_dir / "metrics.json"
    if not path.exists():
        return {}
    return json.loads(path.read_text(encoding="utf-8"))


def load_dataset_summary() -> dict[str, object]:
    monthly = pd.read_csv(ROOT / "data" / "processed" / "monthly_model_ready.csv")
    daily = pd.read_csv(ROOT / "data" / "raw" / "daily_prices.csv")
    macro = pd.read_csv(ROOT / "data" / "raw" / "macro.csv")
    reports = pd.read_csv(ROOT / "data" / "raw" / "financial_report_features_combined_with_manual.csv")
    return {
        "monthly_rows": len(monthly),
        "monthly_cols": monthly.shape[1],
        "daily_rows": len(daily),
        "daily_tickers": daily["ticker"].nunique(),
        "daily_min": daily["date"].min(),
        "daily_max": daily["date"].max(),
        "monthly_min": monthly["decision_date"].min(),
        "monthly_max": monthly["decision_date"].max(),
        "monthly_tickers": monthly["ticker"].nunique(),
        "sectors": monthly["sector"].nunique(),
        "macro_rows": len(macro),
        "report_rows": len(reports),
        "report_tickers": reports["ticker"].nunique(),
    }


def fmt(x, digits: int = 4) -> str:
    try:
        return f"{float(x):.{digits}f}"
    except Exception:
        return str(x)


