def add_contents(doc: Document, toc_pages: dict[str, int] | None = None) -> None:
    add_heading(doc, "СОДЕРЖАНИЕ", level=1)
    toc_pages = toc_pages or {}
    for title, key in TOC_ENTRIES:
        p = doc.add_paragraph()
        p.paragraph_format.first_line_indent = None
        p.paragraph_format.left_indent = Cm(0 if key.startswith("ch") or key in {"intro", "conclusion", "sources"} else 0.6)
        p.paragraph_format.space_after = Pt(0)
        p.paragraph_format.line_spacing = 1.15
        run = p.add_run(f"{title} ")
        set_font(run, size=14)
        dots = "." * max(5, 88 - len(title))
        r2 = p.add_run(dots)
        set_font(r2, size=14)
        page = toc_pages.get(key, "")
        r3 = p.add_run(f" {page}")
        set_font(r3, size=14)
    doc.add_page_break()


def add_expanded_paragraphs(doc: Document, paragraphs: list[str]) -> None:
    for paragraph in paragraphs:
        add_para(doc, paragraph)


def add_code_block(doc: Document, code: str) -> None:
    for line in code.splitlines():
        p = doc.add_paragraph()
        p.paragraph_format.first_line_indent = None
        p.paragraph_format.left_indent = Cm(0.5)
        p.paragraph_format.space_after = Pt(0)
        p.paragraph_format.line_spacing = 1.0
        run = p.add_run(line[:150])
        set_font(run, name="Courier New", size=8.5)


