def chapter3(doc: Document, metrics: dict) -> None:
    add_heading(doc, "ГЛАВА 3. РЕАЛИЗАЦИЯ ML-ПАЙПЛАЙНА И ОЦЕНКА РЕЗУЛЬТАТОВ", level=1, page_break=True)
